package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a dummy JsonPrimitive to initialize JsonTreeReader
    JsonPrimitive element = new JsonPrimitive(0);
    jsonTreeReader = new JsonTreeReader(element);
  }

  @Test
  void nextInt_withNumberToken_returnsIntAndUpdatesState() throws Exception {
    // Arrange
    setStackSize(1);
    setStack(new Object[]{new JsonPrimitive(42)});
    setPathIndices(new int[]{0});
    setPathNames(new String[32]);

    // Spy on jsonTreeReader to mock peek() method only
    JsonTreeReader spyReader = spy(jsonTreeReader);
    doReturn(JsonToken.NUMBER).when(spyReader).peek();

    // Replace the private peekStack() method via reflection to return new JsonPrimitive(42)
    setPeekStackReturnValue(spyReader, new JsonPrimitive(42));

    // Act
    int result = spyReader.nextInt();

    // Assert
    assertEquals(42, result);
    assertEquals(0, getStackSize());
    assertEquals(1, getPathIndices()[0]);
  }

  @Test
  void nextInt_withStringToken_returnsIntAndUpdatesState() throws Exception {
    // Arrange
    setStackSize(1);
    setStack(new Object[]{new JsonPrimitive("123")});
    setPathIndices(new int[]{5});
    setPathNames(new String[32]);

    JsonTreeReader spyReader = spy(jsonTreeReader);
    doReturn(JsonToken.STRING).when(spyReader).peek();

    // Replace the private peekStack() method via reflection to return new JsonPrimitive("123")
    setPeekStackReturnValue(spyReader, new JsonPrimitive("123"));

    // Act
    int result = spyReader.nextInt();

    // Assert
    assertEquals(123, result);
    assertEquals(0, getStackSize());
    assertEquals(6, getPathIndices()[0]);
  }

  @Test
  void nextInt_withInvalidToken_throwsIllegalStateException() throws Exception {
    JsonTreeReader spyReader = spy(jsonTreeReader);
    doReturn(JsonToken.BEGIN_ARRAY).when(spyReader).peek();

    IllegalStateException thrown = assertThrows(IllegalStateException.class, spyReader::nextInt);
    assertTrue(thrown.getMessage().contains("Expected NUMBER but was BEGIN_ARRAY"));
  }

  // Helper methods to set private fields via reflection

  private void setStack(Object[] stack) throws Exception {
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    stackField.set(jsonTreeReader, stack);
  }

  private Object[] getStack() throws Exception {
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    return (Object[]) stackField.get(jsonTreeReader);
  }

  private void setStackSize(int size) throws Exception {
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, size);
  }

  private int getStackSize() throws Exception {
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    return stackSizeField.getInt(jsonTreeReader);
  }

  private void setPathIndices(int[] indices) throws Exception {
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    pathIndicesField.set(jsonTreeReader, indices);
  }

  private int[] getPathIndices() throws Exception {
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    return (int[]) pathIndicesField.get(jsonTreeReader);
  }

  private void setPathNames(String[] names) throws Exception {
    Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
    pathNamesField.setAccessible(true);
    pathNamesField.set(jsonTreeReader, names);
  }

  // Helper to override private peekStack() method to return a specific value
  private void setPeekStackReturnValue(JsonTreeReader spyReader, Object returnValue) throws Exception {
    Method peekStackMethod = JsonTreeReader.class.getDeclaredMethod("peekStack");
    peekStackMethod.setAccessible(true);

    // Use a real invocation handler that calls the original method except for peekStack()
    // Since peekStack() is private, we cannot mock it via Mockito directly.
    // Instead, use doAnswer to intercept calls to peekStack() via reflection.

    // To intercept calls to private method peekStack(), we use a spy and override with doAnswer
    // But Mockito cannot mock private methods directly, so we replace the method call in nextInt() with reflection

    // Instead, redefine nextInt() method via reflection to call peekStack() replaced by returnValue
    // But this is complicated.

    // Alternative: Use a subclass to override peekStack(), but peekStack() is private, so not possible.

    // So, we replace peekStack() call in nextInt() by temporarily setting the stack top to returnValue,
    // and call the real peekStack() method.

    // So set the stack top to returnValue for spyReader's internal stack.

    // Get the stack field from spyReader
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);

    // Replace the top of stack with returnValue
    int stackSize = getStackSizeFromInstance(spyReader);
    if (stackSize == 0) {
      // Increase stack size to 1 and set the stack top
      setStackSizeForInstance(spyReader, 1);
      if (stack.length < 1) {
        Object[] newStack = new Object[32];
        System.arraycopy(stack, 0, newStack, 0, stack.length);
        stack = newStack;
        stackField.set(spyReader, stack);
      }
    }
    stack[stackSize - 1] = returnValue;
  }

  private int getStackSizeFromInstance(JsonTreeReader instance) throws Exception {
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    return stackSizeField.getInt(instance);
  }

  private void setStackSizeForInstance(JsonTreeReader instance, int size) throws Exception {
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(instance, size);
  }
}
